import { HttpClient, HttpContext, HttpResponse } from '@angular/common/http';
import { Observable } from 'rxjs';
import { filter, map } from 'rxjs/operators';
import { StrictHttpResponse } from '../../strict-http-response';
import { RequestBuilder } from '../../request-builder';

export interface ApiuserupdateParams {
  body: {
    idUser: string;
    firstName: string;
    surName: string;
    email: string;
    role: string;
    photo: string;
  };
}

export function apiuserupdate(http: HttpClient, rootUrl: string, params: ApiuserupdateParams, context?: HttpContext): Observable<StrictHttpResponse<any>> {
  const rb = new RequestBuilder(rootUrl, apiuserupdate.PATH, 'put');
  if (params) { rb.body(params.body, 'application/json'); }
  return http.request(rb.build({ responseType: 'json', accept: 'application/json', context })).pipe(
    filter((r: any): r is HttpResponse<any> => r instanceof HttpResponse),
    map((r: HttpResponse<any>) => r as StrictHttpResponse<any>)
  );
}
apiuserupdate.PATH = '/user/update';